def solve(edges, n):
    parent = list(range(n))
    rank = [1] * n

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        rootX = find(x)
        rootY = find(y)
        if rootX == rootY: return False

        if rank[rootX] > rank[rootY]:
            parent[rootY] = rootX
        elif rank[rootX] < rank[rootY]:
            parent[rootX] = rootY
        else:
            parent[rootY] = rootX
            rank[rootX] += 1
        return True

    components = n
    extras = 0

    for x, y in edges:
        if union(x, y):
            components -= 1
        else:
            extras += 1

    if extras < components - 1: return -1
    return components - 1

