    dp[0][0] = True
    for i in range(1, len(nums) + 1):
        for j in range(target + 1):
            if nums[i-1] <= j:
                dp[i][j] = dp[i-1][j] or dp[i-1][j-nums[i-1]]
            else:
                dp[i][j] = dp[i-1][j]
