def solve(nums):
    class TrieNode:
        def __init__(self):
            self.left = None
            self.right = None

    root = TrieNode()
    for num in nums:
        node = root
        for bit in range(31, -1, -1):
            bit_val = (num >> bit) & 1
            if bit_val == 0:
                if not node.left:
                    node.left = TrieNode()
                node = node.left
            else:
                if not node.right:
                    node.right = TrieNode()
                node = node.right

    max_xor = 0
    for num in nums:
        current_max_xor = 0
        node = root
        for bit in range(31, -1, -1):
            bit_val = (num >> bit) & 1
            if bit_val == 0:
                if node.right:
                    current_max_xor |= (1 << bit)
                    node = node.right
                else:
                    node = node.left
            else:
                if node.left:
                    current_max_xor |= (1 << bit)
                    node = node.left
                else:
                    node = node.right
        max_xor = max(max_xor, current_max_xor)
    return max_xor
